import { NavLink } from "react-router-dom";
function Navbar (){
    return(
        <div style={{display:'flex',justifyContent:'center',gap:'18px',backgroundColor:'grey',width:'100vw',height:'40px',alignItems:'center'}}>
            <NavLink to="/">
                Home
            </NavLink>
            <NavLink to="/pastes">
                All Pastes
            </NavLink>
        </div>
    )
}
export default Navbar;
